diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..8a3f9714912a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2229,6 +2229,31 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return BitOp;
     }

+    Value *Amt = II->getArgOperand(2);
+    KnownBits KnownAmt = computeKnownBits(Amt, 0, II);
+    if (KnownAmt.getMaxValue().ult(BitWidth)) {
+      // fshl(X, 0, Amt) --> shl X, Amt
+      // fshl(X, undef, Amt) --> shl X, Amt
+      if (IID == Intrinsic::fshl && (match(Op1, m_ZeroInt()) || match(Op1, m_Undef())))
+        return BinaryOperator::CreateShl(Op0, Amt);
+
+      // fshr(0, X, Amt) --> lshr X, Amt
+      // fshr(undef, X, Amt) --> lshr X, Amt
+      if (IID == Intrinsic::fshr && (match(Op0, m_ZeroInt()) || match(Op0, m_Undef())))
+        return BinaryOperator::CreateLShr(Op1, Amt);
+    }
+
+    if (IID == Intrinsic::fshl && (match(Op1, m_ZeroInt()) || match(Op1, m_Undef())) &&
+        isPowerOf2_32(BitWidth)) {
+      Value *ShAmt = Builder.CreateAnd(Amt, ConstantInt::get(Ty, BitWidth - 1));
+      return BinaryOperator::CreateShl(Op0, ShAmt);
+    }
+
+    if (IID == Intrinsic::fshr && (match(Op0, m_ZeroInt()) || match(Op0, m_Undef())) &&
+        isPowerOf2_32(BitWidth)) {
+      Value *ShAmt = Builder.CreateAnd(Amt, ConstantInt::get(Ty, BitWidth - 1));
+      return BinaryOperator::CreateLShr(Op1, ShAmt);
+    }
     // Left or right might be masked.
     if (SimplifyDemandedInstructionBits(*II))
       return &CI;

